import javax.inject._
import play.api.mvc._
import slick.driver.MySQLDriver.api._
import models.Product

class ProductSearchController @Inject()(val db: Database) extends Controller {

  def searchProducts = Action { request =>
    val searchParams = request.queryString
    val query = sql"""
      SELECT * FROM products
      WHERE ${sqlFragment(buildWhereClause(searchParams))}
    """.as[Product]
    val products = db.run(query)
    Ok(products)
  }

  private def buildWhereClause(params: Map[String, Seq[String]]): String = {
    params.map { case (key, values) => s"$key IN ('${values.mkString("','")}')" }.mkString(" AND ")
  }
}